  ('customs-7fec267e-moex-00091', 'customs-7fec267e', 'customs-7fec267e-moex-113-6948958a', 'sub-customs-7fec267e-01', NULL, 'single_choice', '某國自然失業率4%，總失業率7%，當畢業季來臨，摩擦性失業增加，根據奧肯法則（Okun’sLaw），產 出缺口會：', '["擴大", "不變", "縮小", "不一定"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:22:21+00:00", "source_pdf_sha1": "3fac22dc26b5", "answer_pdf_sha1": "8e5c03118776", "source_family": "moex-gov-tw", "moex": {"exam_code": "113040", "c": "142", "s": "0903", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "經濟學概要", "year": "113", "exam_name": "113年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 30, "answer_corrected": false, "flags": [], "civil_slug": "customs", "civil_category": "一般行政"}'::jsonb, NULL),
