  ('customs-7fec267e-moex-00093', 'customs-7fec267e', 'customs-7fec267e-moex-113-6948958a', 'sub-customs-7fec267e-01', NULL, 'single_choice', '國民所得之變動有高有低，一系列的短期波動現象稱之為何？', '["衰退", "折舊", "經濟成長", "景氣循環"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:22:21+00:00", "source_pdf_sha1": "3fac22dc26b5", "answer_pdf_sha1": "8e5c03118776", "source_family": "moex-gov-tw", "moex": {"exam_code": "113040", "c": "142", "s": "0903", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "經濟學概要", "year": "113", "exam_name": "113年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 32, "answer_corrected": false, "flags": [], "civil_slug": "customs", "civil_category": "一般行政"}'::jsonb, NULL),
  ('customs-7fec267e-moex-00094', 'customs-7fec267e', 'customs-7fec267e-moex-113-6948958a', 'sub-customs-7fec267e-01', NULL, 'single_choice', '某一封閉經濟體的生產函數為：Y=AK1/3L2/3，其中Y為總產出（GDP）、技術水準A=3（單位）、資本 投入量K=512（單位）、勞動投入量L=1,000（人）。若勞動投入人口占總人口的比例為0.8，該經濟體 每人平均GDP為何？', '["1.28", "1.92", "2.4", "3"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:22:21+00:00", "source_pdf_sha1": "3fac22dc26b5", "answer_pdf_sha1": "8e5c03118776", "source_family": "moex-gov-tw", "moex": {"exam_code": "113040", "c": "142", "s": "0903", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "經濟學概要", "year": "113", "exam_name": "113年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 33, "answer_corrected": false, "flags": [], "civil_slug": "customs", "civil_category": "一般行政"}'::jsonb, NULL),
  ('customs-7fec267e-moex-00095', 'customs-7fec267e', 'customs-7fec267e-moex-113-6948958a', 'sub-customs-7fec267e-01', NULL, 'single_choice', '假設甲國的總合產出 Y 可以用生產函數：Y=AKαN1-α來描述，其中 A 是總要素生產力（total factor productivity）、K是資本、N是勞動。若甲國的資本所得份額（capital income share）是0.25，且今年有 8%的總合產出成長、16%的資本成長、2%的勞動成長，則甲國的總要素生產力成長（totalfactorproductivity growth）有多少？', '["1.5%", "2.5%", "3.5%", "5.5%"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:22:21+00:00", "source_pdf_sha1": "3fac22dc26b5", "answer_pdf_sha1": "8e5c03118776", "source_family": "moex-gov-tw", "moex": {"exam_code": "113040", "c": "142", "s": "0903", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "經濟學概要", "year": "113", "exam_name": "113年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 34, "answer_corrected": false, "flags": [], "civil_slug": "customs", "civil_category": "一般行政"}'::jsonb, NULL)
